// n8n-marcin/14-monitor-sasiadow.json — Zbierz Wiadomości Sąsiadów
// Purpose: Scrape news from neighboring powiats, AI summary, Telegram digest
// NOT for: collecting Kraśnik news (that's News Collector)

const geminiKey = $env.GEMINI_API_KEY || '';

// Sources: neighboring powiats via Dziennik Wschodni + official sites
const sources = [
  { name: 'DW Janów Lubelski', url: 'https://www.dziennikwschodni.pl/janow-lubelski/', powiat: 'Janów Lubelski' },
  { name: 'DW Opole Lubelskie', url: 'https://www.dziennikwschodni.pl/opole-lubelskie/', powiat: 'Opole Lubelskie' },
  { name: 'Powiat Janowski', url: 'https://powiatjanowski.pl/category/aktualnosci/', powiat: 'Janów Lubelski' },
  { name: 'Lublin112 Opole', url: 'https://www.lublin112.pl/category/wiadomosci-z-regionu/opole-lubelskie/', powiat: 'Opole Lubelskie' }
];

// Fetch all sources in parallel
const fetchPage = async (src) => {
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET', url: src.url,
      options: { redirect: { followRedirects: true }, response: { response: { responseFormat: 'text' } } }
    });
    const body = typeof html === 'string' ? html : (html.data || html.body || '');
    return { ...src, html: body, error: null };
  } catch (e) {
    return { ...src, html: '', error: e.message };
  }
};

const results = await Promise.all(sources.map(fetchPage));

// Extract article titles and links from HTML
const allArticles = [];

for (const r of results) {
  if (!r.html) continue;

  // Generic extraction: find <a> tags with article-like titles
  // DW pattern: <a href="/janow-lubelski/...">Title</a>
  // Powiat pattern: <a href="https://powiatjanowski.pl/...">Title</a>
  const articleRegex = /<a[^>]+href=["']([^"']+)["'][^>]*>([^<]{15,200})<\/a>/gi;
  let match;
  const seen = new Set();

  while ((match = articleRegex.exec(r.html)) !== null && allArticles.length < 100) {
    const href = match[1];
    const title = match[2].replace(/\s+/g, ' ').trim();

    // Filter: only article-like links (not navigation, not categories)
    const isArticle = (
      (href.includes('/janow-lubelski/') || href.includes('/opole-lubelskie/') ||
       href.includes('powiatjanowski.pl/') || href.includes('lublin112.pl/')) &&
      !href.includes('/category/') && !href.includes('/tag/') &&
      !href.includes('/page/') && !href.includes('#') &&
      title.length > 20 && title.length < 200 &&
      !title.includes('Czytaj więcej') && !title.includes('Strona główna')
    );

    if (isArticle && !seen.has(title)) {
      seen.add(title);
      allArticles.push({
        title,
        url: href.startsWith('http') ? href : (new URL(href, r.url)).toString(),
        source: r.name,
        powiat: r.powiat
      });
    }
  }
}

if (allArticles.length < 3) {
  return [{ json: { skip: true, reason: 'Za mało artykułów z sąsiednich powiatów: ' + allArticles.length } }];
}

// Ask Gemini to create a digest
const articleList = allArticles.slice(0, 30).map((a, i) =>
  `${i + 1}. [${a.powiat}/${a.source}] ${a.title}`
).join('\n');

const prompt = `Jesteś asystentem Marcina Nastarowicza z Biura Starosty Powiatu Kraśnickiego.
Poniżej lista artykułów z SĄSIEDNICH powiatów (Janów Lubelski, Opole Lubelskie).

Przygotuj KRÓTKI tygodniowy digest (max 10 pozycji) z najciekawszymi wiadomościami.
Dla każdej pozycji napisz 1 zdanie co się dzieje.
Na końcu dodaj 1-2 zdania: co z tego Kraśnik może wyciągnąć / co jest inspirujące.

Format:
🏘️ CO U SĄSIADÓW — tydzień [data]

📍 Janów Lubelski:
• [wiadomość 1]
• [wiadomość 2]

📍 Opole Lubelskie:
• [wiadomość 1]

💡 Inspiracja dla Kraśnika: [1-2 zdania]

ARTYKUŁY:
${articleList}`;

let digest = '';
try {
  const aiResult = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent?key=' + geminiKey,
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.4, maxOutputTokens: 1000 }
    },
    json: true
  });
  digest = aiResult.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) { console.log('Gemini error:', e.message); }

if (!digest) {
  return [{ json: { skip: true, reason: 'Gemini nie wygenerował digestu' } }];
}

// Truncate for Telegram
if (digest.length > 4000) {
  digest = digest.substring(0, 3950) + '\n\n... ciąg dalszy na portalu';
}

return [{ json: { skip: false, telegram: digest, articleCount: allArticles.length, sources: results.map(r => r.name + ': ' + (r.error || 'OK')).join(', ') } }];
